// ============================================
// PARSER MESSAGE WHATSAPP
// ============================================
const body = $input.first().json;

let from, message, name;

// Format Meta Cloud API
if (body.entry) {
  const msg     = body.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
  const contact = body.entry?.[0]?.changes?.[0]?.value?.contacts?.[0];
  from    = msg?.from || '';
  message = msg?.text?.body || '';
  name    = contact?.profile?.name || 'Client';
}
// Format WPPConnect / Baileys / Test
else {
  from    = (body.from || '').replace('@s.whatsapp.net', '');
  message = body.body || body.text || body.message || '';
  name    = body.sender?.pushname || body.name || 'Client';
}

const msgLower = message.toLowerCase();

// Extraire ref produit : ref:123
const refMatch  = message.match(/ref:(\d+)/);
const produitId = refMatch ? refMatch[1] : null;

// Extraire ville du message
let ville = '';
if (/tanger|طنجة/.test(msgLower))       ville = 'Tanger';
else if (/casa|كازا|casablanca/.test(msgLower)) ville = 'Casablanca';
else if (/rabat|رباط/.test(msgLower))    ville = 'Rabat';
else if (/agadir|أكادير/.test(msgLower)) ville = 'Agadir';

// Détecter l'intention
let intent = 'product_inquiry'; // défaut si ref présent
if (!produitId) {
  if (/salut|bonjour|salam|أهلا|مرحبا|السلام/.test(msgLower)) intent = 'greeting';
  else if (/promo|عرض|تخفيض|offre/.test(msgLower))             intent = 'promo';
  else if (/livraison|توصيل/.test(msgLower))                   intent = 'delivery';
  else if (/prix|ثمن|كم/.test(msgLower))                       intent = 'price';
  else if (/stop|désinscrire/.test(msgLower))                  intent = 'stop';
  else                                                          intent = 'unknown';
}

return [{
  json: { from, name, message, intent, produitId, ville, timestamp: new Date().toISOString() }
}];

// ============================================
// RÉPONSE QUAND CLIENT A CLIQUÉ SUR UN PRODUIT
// ============================================
const parsed  = $('🧠 Parser Message').first().json;
const produit = $('🐟 Récupérer Produit').first().json;
const { from, name } = parsed;
const prenom  = name?.split(' ')[0] || 'صديقي';

if (!produit || produit.message) {
  return [{ json: {
    from,
    msgClient: `🐟 عذراً ${prenom}، هاد المنتج ما لقيناهش دابا.\n\nشوف جميع العروض:\n👉 ${process.env.FRONTEND_URL || 'http://localhost:5173'}`,
    msgVendeur: null,
    vendeurPhone: null
  }}];
}

const vendeur = produit.seller || {};
const prix    = `${Number(produit.price).toLocaleString('fr-FR')} MAD/${produit.unit}`;

// Message client — confirmation + infos produit
const msgClient = `✅ *تم استلام طلبك!*

مرحباً ${prenom} 👋

🐟 *${produit.name}*
💰 ${prix}
📍 ${produit.city || vendeur.city || 'Maroc'}
👨‍🍳 البائع: ${vendeur.name || 'SamakMarket'}

⏳ *البائع سيتواصل معك قريباً!*
عادةً خلال 15-30 دقيقة ⏱️

_شكراً على ثقتك في SamakMarket_ 🌊`;

// Message vendeur — notification lead
const msgVendeur = `🔔 *طلب جديد على SamakMarket!*
━━━━━━━━━━━━━━━━━━
👤 *العميل:* ${name}
📱 *الهاتف:* +${from}
🐟 *المنتج:* ${produit.name}
💰 *السعر:* ${prix}
📍 *المدينة:* ${produit.city || 'Maroc'}
⏰ *الوقت:* ${new Date().toLocaleTimeString('fr-FR')}
━━━━━━━━━━━━━━━━━━
✅ *تواصل معه الآن!*
📲 https://wa.me/${from}`;

return [{ json: {
  from,
  msgClient,
  msgVendeur,
  vendeurPhone: vendeur.whatsapp || vendeur.phone || null,
  produitNom: produit.name
}}];

// ============================================
// RÉPONSE GÉNÉRALE (sans ref produit)
// ============================================
const parsed = $('🧠 Parser Message').first().json;
const promos = $('🔥 Récupérer Promos').first().json || [];
const { from, name, intent, ville } = parsed;
const prenom  = name?.split(' ')[0] || 'صديقي';
const baseUrl = process.env.FRONTEND_URL || 'http://localhost:5173';

let msgClient = '';

if (intent === 'greeting') {
  msgClient = `🐟 *أهلاً ${prenom}!*

مرحباً بك في *SamakMarket* 🌊
السمك الطازج من البحر لديك مباشرة!

اختر:
1️⃣ عروض اليوم 🔥
2️⃣ ابحث عن بائع 📍
3️⃣ معلومات التوصيل 🚚

أو تصفح موقعنا:
👉 ${baseUrl}`;
}
else if (intent === 'promo') {
  const list = Array.isArray(promos) ? promos.slice(0,3) : [];
  let ligne = list.map((p,i) => `${i+1}️⃣ *${p.name}* — ${p.price} MAD/${p.unit} 📍${p.city||'Maroc'}`).join('\n');
  msgClient = `🔥 *عروض اليوم على SamakMarket!*\n\n${ligne||'ما كاينش عروض دابا'}\n\n👉 ${baseUrl}`;
}
else if (intent === 'delivery') {
  msgClient = `🚚 *التوصيل*\n\n✅ 2-4 ساعات\n📍 طنجة، كازا، رباط، أكادير\n💰 مجاني فوق 150 درهم\n\n👉 ${baseUrl}`;
}
else {
  msgClient = `🐟 *SamakMarket*\n\nشكراً ${prenom}!\n\nاكتب: *عروض* أو *بائع* أو *توصيل*\n👉 ${baseUrl}`;
}

return [{ json: { from, msgClient, msgVendeur: null, vendeurPhone: null } }];
